# factorial.tcl

# Function to calculate factorial of a number recursively
# @param n: The number for which to calculate the factorial.
# @return: The factorial of the given number.
proc factorial {n} {
    if {$n == 0 || $n == 1} {
        return 1
    } elseif {$n < 0} {
        return "Factorial is not defined for negative numbers."
    } else {
        return [expr {$n * [factorial [expr {$n - 1}]]}]
    }
}

# Function to handle user input and call factorial function
# @return: The factorial of the input number or an error message.
proc getFactorialInput {} {
    set input ""
    while {1} {
        # Prompt user for input
        puts "Enter a positive integer to compute its factorial (or 'q' to quit):"
        set input [gets stdin]

        # Check if the user wants to quit
        if {[string equal $input "q"]} {
            break
        }

        # Validate the input
        if {[string is integer -strict $input] && $input >= 0} {
            # Input is valid, calculate the factorial
            set result [factorial $input]
            if {[string is integer -strict $result]} {
                puts "The factorial of $input is $result."
                break
            } else {
                puts $result
            }
        } else {
            # Invalid input, prompt again
            puts "Invalid input. Please enter a non-negative integer."
        }
    }
}

# Main script starts here
puts "Welcome to the Factorial Calculator!"
getFactorialInput
puts "Thank you for using the Factorial Calculator!"
