use std::fs::File;
use std::io::{self, Read, Write};

fn main() -> io::Result<()> {
    // Define the path to the input and output files
    let input_file = "input.bin";
    let output_file = "output.txt";

    // Open the input binary file for reading
    let mut file = File::open(input_file)?;

    // Create or open the output text file for writing
    let mut output = File::create(output_file)?;

    // Read the entire content of the binary file into a buffer
    let mut buffer = Vec::new();
    file.read_to_end(&mut buffer)?;

    // Convert each integer in the buffer to an 8-byte string and write to the output file
    for &byte in &buffer {
        write!(&mut output, "{:02X}", byte)?;
    }

    println!("Data has been successfully written to {}", output_file);
    Ok(())
}
```

### Explanation:

1. **Imports**: We import necessary modules from the standard library:
   - `std::fs::File` for file operations.
